        // ".👨‍💻" — man + ZWJ + laptop: visually one glyph, three code points after the dot.
        assert!(!is_valid_prompt_alias(".\u{1F468}\u{200D}\u{1F4BB}"));
    }

    #[test]
    fn parse_lock_rejects_invalid_prompt_alias() {
        let raw = r#"{"model": "m", "promptAliases": ["abc"]}"#;
        assert!(matches!(
            parse_lock(raw),
            Err(LockError::InvalidPromptAlias(_))
        ));
    }

    #[test]
    fn custom_preset_requires_non_empty_command() {
        let missing = AgentConfig {
            preset: AgentPreset::Custom,
            command: None,
        };
        assert_eq!(
            validate_agent_config(&missing).unwrap_err(),
            LockError::CustomAgentMissingCommand
        );

        let empty = AgentConfig {
            preset: AgentPreset::Custom,
            command: Some(vec![]),
        };
        assert_eq!(
            validate_agent_config(&empty).unwrap_err(),
            LockError::CustomAgentMissingCommand
        );

        let ok = AgentConfig {
            preset: AgentPreset::Custom,
            command: Some(vec!["run".to_string()]),
        };
        assert!(validate_agent_config(&ok).is_ok());
    }

    #[test]
    fn claude_and_codex_presets_reject_command() {
        let claude_with_command = AgentConfig {
            preset: AgentPreset::Claude,
            command: Some(vec!["run".to_string()]),
        };
        assert_eq!(
            validate_agent_config(&claude_with_command).unwrap_err(),
            LockError::NonCustomAgentHasCommand
        );

        let codex_with_command = AgentConfig {
            preset: AgentPreset::Codex,
            command: Some(vec!["run".to_string()]),
        };
        assert_eq!(
            validate_agent_config(&codex_with_command).unwrap_err(),
            LockError::NonCustomAgentHasCommand
        );

        let claude_ok = AgentConfig {
            preset: AgentPreset::Claude,
            command: None,
        };
        assert!(validate_agent_config(&claude_ok).is_ok());
    }

    #[test]
    fn resolve_prompt_aliases_uses_override_or_curated_default() {
        let with_override = HlLock {
            model: "m".to_string(),
            backend: Backend::ClaudeCli,
            prompt_aliases: Some(vec![".x".to_string()]),
            agent: None,
        };
        assert_eq!(resolve_prompt_aliases(&with_override), vec![".x".to_string()]);

        let without_override = HlLock {
            model: "m".to_string(),
            backend: Backend::ClaudeCli,
            prompt_aliases: None,
            agent: None,
        };
        assert_eq!(
            resolve_prompt_aliases(&without_override),
            extensions::default_prompt_aliases()
        );
    }

    #[test]
    fn resolve_agent_config_uses_override_or_default() {
        let with_override = HlLock {
            model: "m".to_string(),
            backend: Backend::ClaudeCli,
            prompt_aliases: None,
            agent: Some(AgentConfig {
                preset: AgentPreset::Codex,
                command: None,
            }),
        };
        assert_eq!(
            resolve_agent_config(&with_override),
            AgentConfig {
                preset: AgentPreset::Codex,
                command: None
            }
        );

        let without_override = HlLock {
            model: "m".to_string(),
            backend: Backend::ClaudeCli,
            prompt_aliases: None,
            agent: None,
        };
        assert_eq!(resolve_agent_config(&without_override), default_agent_config());
    }
